def get_all_products():
    return PRODUCTS


def get_product_by_id(product_id):
    return next((p for p in PRODUCTS if p["id"] == product_id), None)


def get_categories():
    seen = []
    for p in PRODUCTS:
        if p["categoria"] not in seen:
            seen.append(p["categoria"])
    return seen


def get_tipos():
    seen = []
    for p in PRODUCTS:
        if p["tipo"] not in seen:
            seen.append(p["tipo"])
    return seen
